#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c) 
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int Mod=1e9+7;
inline void DN(int &x){x>=Mod?x-=Mod:0;}inline void UP(int &x){x<0?x+=Mod:0;}
inline bool Jud(int x){return !(x&3)||(x&3)==3;}
int dp[15][1<<15],G[15],n,m,w[250];
vector<int> f[1<<15];int cnt[1<<15];
inline void debug(int S){for(int i=0;i<n;++i)if(S>>i&1)putchar('1');else putchar('0');}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();m=read();int All=(1<<n)-1;
	w[0]=1;rep(1,m,i)DN(w[i]=w[i-1]<<1); 
	rep(1,m,i){int x=read()-1,y=read()-1;G[x]|=1<<y;}
	for(int S=1;S<(1<<n);++S)cnt[S]=cnt[S>>1]+(S&1);
	for(int S=0;S<(1<<n);++S)if(Jud(S))
	{
		for(int T=S&(S-1);T;T=S&(T-1))if(Jud(T))
		{
			int tmp=1,U=S^T,V=All^S;
			for(int i=0;i<n;++i)
			{
				if(V>>i&1)tmp=1ll*tmp*(w[cnt[G[i]&U]]-1)%Mod;
				if(U>>i&1)tmp=1ll*tmp*w[cnt[G[i]&V]]%Mod;
			}
			f[S].push_back(tmp);
		}
	}
	for(int S=0;S<(1<<n);++S)if(Jud(S))
	{
		int tmp=1;for(int i=0;i<n;++i)
		{
			if(!(S>>i&1))tmp=1ll*tmp*(w[cnt[G[i]&S]]-1)%Mod;
			else tmp=1ll*tmp*w[cnt[G[i]&(All^S)]]%Mod;
		}
		dp[0][S]=tmp;
	}
	for(int i=1;i<n;++i)
	{
		for(int S=0;S<(1<<n);++S)if(Jud(S))
		{
			int p=0;
			for(int T=S&(S-1);T;T=S&(T-1))if(Jud(T))
			{
				dp[i][S]=(1ll*f[S][p]%Mod*dp[i-1][T]+dp[i][S])%Mod;
				++p;
//				printf("%d ( ",i);debug(T);printf(" ) :: %d\n",dp[i][S]);
			}
		}
	}
	int ans=w[m];for(int i=0;i<n;++i)UP(ans-=dp[i][All]);
	printf("%d\n",ans);return 0;
}
